import java.util.HashMap;
import java.util.Map;

public class OrderProcessor {

    private Map<String, Integer> priceList = new HashMap<>();

    // Method to add products and their prices to the price list
    public void addProduct(String product, int price) {
        priceList.put(product, price);
    }

    // Method to split the order string and retrieve the price
    public int getOrderPrice(String orderString) {
        String[] orderData = orderString.split("\\s+");
        String[] productDetails = orderData[0].split("–");
        int productPrice = priceList.get(productDetails[1]);
        int orderPrice = Integer.parseInt(orderData[1]) * productPrice;
        return orderPrice;
    }

    public static void main(String[] args) {
        OrderProcessor processor = new OrderProcessor();

        // Add products and their prices
        processor.addProduct("Puppy", 50);
        processor.addProduct("Dog", 30);

        // Process an order string
        String orderString = "Puppy–5";
        int price = processor.getOrderPrice(orderString);
        System.out.println("Order Price: " + price); // Output: Order Price: 250
    }
}
```

